-- 2026-06-19: shoulder_calcific — фазы «Путь» + структурированные критерии перехода.
-- Кальцифицирующий тендинит ротаторной манжеты плеча, КОНСЕРВАТИВНОЕ ведение (первая линия).
--
-- Источник: PROTOCOLS досье кальцифицирующего тендинита + PROTOCOLS/shoulder/_extractions.json
-- (объект shoulder_calcific). Anchor = symptom_driven: переход определяется фазой
-- болевого/воспалительного процесса и достижением критериев, НЕ календарём; недели в
-- subtitle/duration_weeks — ориентир, не точка перехода. 5 фаз (0–4).
--
-- ⚠️ НЕТИПИЧНАЯ СЕМАНТИКА ФАЗЫ 0 (важно для логики стартовой фазы):
--   Фаза 0 здесь — НЕ prehab (подготовка к операции), а ПОСТПРОЦЕДУРНЫЙ УСЛОВНЫЙ период.
--   Применяется ТОЛЬКО если пациенту делали процедуру (барботаж/иглоукалывание/промывание
--   кальцината — barbotage/needling/lavage). При чисто консервативном ведении (без процедуры)
--   восстановление СТАРТУЕТ С ФАЗЫ 1, фаза 0 пропускается. У фазы 0 свои критерии перехода
--   (включены). Стартовая фаза выбирается вручную куратором с учётом факта процедуры.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их
-- СРАЗУ в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки.
--
-- Контент в ПАЦИЕНТСКОМ регистре (без клинич. жаргона/цитат) — Vadim калибрует через
-- AdminContent. «Резорбтивная фаза» подана как «фаза рассасывания отложения».
--
-- Классификация критериев: criterion_type='measurement' ТОЛЬКО для того, что система хранит
-- и может авто-проверить — боль ВАШ (measurement_type='vas_score', source='pain'; код как в
-- ACL-seed 20260518, чтобы D2 читал единый код против pain_entries.vas_score). Числовые пороги
-- ROM (градусы сгибания/отведения), недели с процедуры, симметрия силы система НЕ хранит →
-- 'instructor_check' с порогом в ТЕКСТЕ label (куратор вводит очно). Качественное да/нет от
-- пациента → 'self_report'. Диапазоны (140–150°) кодированы нижней границей.
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/knee/другие shoulder_* program_type (фильтр по program_type='shoulder_calcific').

BEGIN;

-- =====================================================
-- 1. Фазы shoulder_calcific (контент «Путь»), 5 фаз 0–4
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
