-- =====================================================
-- 2. Структурированные критерии перехода shoulder_calcific
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 0 → Фаза 1 (период после процедуры → острая фаза)
  (0, 'postproc_pain_settled',  'Острая боль после процедуры стихла — можете двигать рукой для умывания и одевания', 'self_report',      NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Острая боль после процедуры стихла настолько, что можете двигать рукой для умывания и одевания?', 'Оцените возможность лёгких бытовых движений рукой', 10::smallint, TRUE),
  (0, 'no_infection_signs_p0',  'Нет признаков инфекции (температуры, покраснения, горячего отёка, гноя)',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (0, 'week_since_procedure',   'Прошла не менее 1 недели с момента процедуры',                                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (0, 'rest_pain_le4_p0',       'Боль в покое не более 4 из 10',                                              'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 40::smallint, TRUE),
  (0, 'pendulum_no_guard_p0',   'Маятниковое упражнение получается без скованного замирания плеча',            'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 1 → Фаза 2 (острая фаза → возврат движения и контроля)
  (1, 'rest_pain_le4_p1',       'Боль в покое не более 3–4 из 10, сон без частых пробуждений',                'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 10::smallint, TRUE),
  (1, 'passive_flex_90_p1',     'Подъём руки вперёд с поддержкой не менее 90° без резкой боли',               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'no_infection_acute_p1',  'Нет признаков общей инфекции, острый пик боли пройден',                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'er_preserved_p1',        'Сохранён поворот руки наружу (нет картины замороженного плеча)',             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (1, 'adl_below_shoulder_p1',  'Получается выполнять лёгкие бытовые действия рукой ниже уровня плеча',        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете выполнять лёгкие бытовые действия рукой ниже уровня плеча?', 'Например, умыться, причесаться, держать кружку', 50::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (возврат движения и контроля → сила и выносливость)
  (2, 'active_flex_140_p2',     'Активный подъём руки вперёд не менее 140–150°',                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'active_abd_140_p2',      'Активное отведение руки в сторону не менее 140° без выраженной болезненной дуги', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'no_painful_arc_p2',      'Болезненной дуги нет, плечо и лопатка двигаются слаженно',                   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'sleep_on_side_p2',       'Можете спать на больной стороне без пробуждений от боли',                    'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете спать на больной стороне без пробуждений от боли?', 'Оцените по нескольким ночам', 40::smallint, FALSE),
  (2, 'cuff_isometric_p2',      'Удерживаете лёгкое статическое напряжение мышц манжеты без боли и подмен',    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (сила и выносливость → возврат к спорту и нагрузкам)
  (3, 'rom_symmetric_p3',       'Активный объём движений полный или в пределах ~10° от здоровой руки',         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'strength_symmetric_p3',  'Сила плеча и лопатки симметрична здоровой стороне, без явной слабости',       'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'adl_work_pain_free_p3',  'Повседневные и рабочие действия, включая движения над головой, безболезненны', 'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Безболезненны повседневные и рабочие действия, включая движения над головой?', 'Оцените по типичной неделе', 30::smallint, TRUE),
  (3, 'rhythm_under_load_p3',   'Плечо и лопатка работают слаженно под нагрузкой, без подмен',                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (3, 'lift_hold_weight_p3',    'Можете поднять и удержать бытовой вес без боли',                             'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете поднять и удержать привычный бытовой вес без боли?', 'Например, сумку с продуктами, кастрюлю', 50::smallint, FALSE),

  -- Фаза 4 → выход из «Пути» (возврат к полной активности)
  (4, 'return_to_sport_p4',     'Вернулись к желаемому уровню активности и спорта без боли и ограничений',     'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Вернулись к желаемому уровню активности и спорта без боли и ограничений?', 'Сравните с тем, как было до проблемы с плечом', 10::smallint, TRUE),
  (4, 'full_control_load_p4',   'Полный безболезненный контроль плеча под нагрузкой и над головой, симметрично здоровому', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'strength_rom_symm_p4',   'Симметрия силы и объёма движений со здоровой стороной (оценивает куратор очно)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (4, 'confidence_in_shoulder_p4', 'Уверены в плече при привычных нагрузках и спорте',                        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Уверены в плече при привычных нагрузках и спорте?', 'Психологическая уверенность так же важна, как физическое восстановление', 40::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_calcific' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
